#include <vector>
#include <cstring>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_jacobi_1d(int tsteps,
                      int n,
                      std::vector<double> &A,
                      std::vector<double> &B) {
    // Ensure the vectors are at least length n
    if ((int)A.size() < n || (int)B.size() < n) return;

    // Getting raw pointers for faster access
    double *a = A.data();
    double *b = B.data();

    const double coeff = 0.33333;

#pragma omp parallel for
    for (int t = 0; t < tsteps; ++t) {
        // First half-step: compute B from A
        for (int i = 1; i < n - 1; ++i) {
            b[i] = coeff * (a[i - 1] + a[i] + a[i + 1]);
        }

        // Second half-step: compute A from B
        for (int i = 1; i < n - 1; ++i) {
            a[i] = coeff * (b[i - 1] + b[i] + b[i + 1]);
        }
    }
}
