// Optimised Bicg kernel – identical behaviour, faster on x86‑64 (gcc O2, OpenMP)
#include <vector>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_bicg(int m, int n,
                 std::vector<std::vector<double>>& A,
                 std::vector<double>& s,
                 std::vector<double>& q,
                 std::vector<double>& p,
                 std::vector<double>& r)
{
    /* zero initialise s[0..m-1] before the main loop for better cache behaviour */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < m; ++i) {
        s[i] = 0.0;
    }

    /* Main double loop – fused for cache‑efficiency */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double q_val = 0.0;
        for (int j = 0; j < m; ++j) {
            double const a_ij = A[i][j];
            s[j] += r[i] * a_ij;        // s[j] = s[j] + r[i]*A[i][j]
            q_val += a_ij + p[j];        // q_val += A[i][j] + p[j]
        }
        q[i] = q_val;
    }
}
