// Optimized Floyd‑Warshall
#include <vector>
#include <algorithm>
#include <cstddef>
#include <omp.h>

// Helper to flat index into 2‑D vector
inline int idx(int i, int j, int n) { return i * n + j; }

void kernel_floyd_warshall(int n, std::vector<std::vector<int>>& path) {
    // Flatten into a single contiguous array for better cache locality
    std::vector<int> flat(n * n);
    for (int i = 0; i < n; ++i)
        std::copy(path[i].begin(), path[i].end(), flat.begin() + i * n);

#pragma omp parallel for schedule(static)
    for (int k = 0; k < n; ++k) {
        const int kBase = k * n;
        for (int i = 0; i < n; ++i) {
            const int iBase = i * n;
            const int ik = flat[iBase + k];
            for (int j = 0; j < n; ++j) {
                const int alt = ik + flat[kBase + j];
                int &dest = flat[iBase + j];
                if (alt < dest) dest = alt;
            }
        }
    }

    // Copy back to the original structure
    for (int i = 0; i < n; ++i)
        std::copy(flat.begin() + i * n, flat.begin() + (i + 1) * n, path[i].begin());
}
