```cpp
#include <vector>
#include <cstddef>
#include <omp.h>

void kernel_syr2k(int n, int m,
                  double alpha,
                  double beta,
                  std::vector<std::vector<double>>& C,
                  std::vector<std::vector<double>>& A,
                  std::vector<std::vector<double>>& B)
{
    // The loops are deliberately kept in the same order as the reference
    // implementation to preserve numerical results.  We simply add
    // parallelism and use local pointers for cache friendliness.
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        // Scale the k‑th row of the lower triangle
        double *Ci      = C[i].data();
        double *Ai      = A[i].data();   // A[i][k]
        double *Bi      = B[i].data();   // B[i][k]
        for (int j = 0; j <= i; ++j) {
            Ci[j] *= beta;
        }

        // Accumulate outer products
        for (int k = 0; k < m; ++k) {
            double aik = Ai[k];
            double bik = Bi[k];
            for (int j = 0; j <= i; ++j) {
                double Bjk = B[j][k];
                double Ajk = A[j][k];
                Ci[j] += alpha * (Ajk * bik + Bjk * aik);
            }
        }
    }
}
