/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_atax(int m, int n,
                 std::vector<std::vector<double>>& A,
                 std::vector<double>& x,
                 std::vector<double>& y,
                 std::vector<double>& tmp)
{
    /* Zero y in parallel */
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < n; ++j) {
        y[j] = 0.0;
    }

    /* Main double loop */
    for (int i = 0; i < m; ++i) {
        double sum = 0.0;
        /* First inner loop - compute tmp[i] = A[i]·x */
        const std::vector<double>& Ai = A[i];
        #pragma omp simd reduction(+:sum)
        for (int j = 0; j < n; ++j) {
            sum += Ai[j] * x[j];
        }
        tmp[i] = sum;

        /* Second inner loop - accumulate into y */
        #pragma omp simd
        for (int j = 0; j < n; ++j) {
            y[j] += Ai[j] * sum;
        }
    }
}
