/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_mvt(int n,
                std::vector<double>& x1,
                std::vector<double>& x2,
                std::vector<double>& y_1,
                std::vector<double>& y_2,
                std::vector<std::vector<double>>& A) {

    const double* const y1 = y_1.data();
    const double* const y2 = y_2.data();
    double* const X1 = x1.data();
    double* const X2 = x2.data();

    /* First part: X1[i] += sum_j A[i][j] * y1[j]  */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double sum = 0.0;
        const std::vector<double>& row = A[i];
        const double* restrict a = row.data();
        for (int j = 0; j < n; ++j) {
            sum += a[j] * y1[j];
        }
        X1[i] += sum;
    }

    /* Second part: X2[i] += sum_j A[j][i] * y2[j]  */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double sum = 0.0;
        for (int j = 0; j < n; ++j) {
            sum += A[j][i] * y2[j];
        }
        X2[i] += sum;
