/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_trisolv(int n,
		    std::vector<std::vector<double>>& L,
		    std::vector<double>& x,
		    std::vector<double>& b) {
    /*  Flatten the triangular matrix in a contiguous buffer.
        The layout is row‑major: L[i][j] -> flat[i * n + j]. */
    const std::size_t stride = static_cast<std::size_t>(n);
    std::vector<double> flat_L(static_cast<std::size_t>(n) * n);

    for (int i = 0; i < n; ++i) {
        for (int j = 0; j <= i; ++j) {   // only lower‑triangular part is used
            flat_L[static_cast<std::size_t>(i) * stride + j] = L[i][j];
        }
    }

    /* Forward substitution:  x = L^{-1} b  (L is lower‑triangular) */
    for (int i = 0; i < n; ++i) {
        double val = b[i];
        const std::size_t row_off = static_cast<std::size_t>(i) * stride;

        /* Unroll the inner loop to improve cache reuse and enable SIMD. */
        int j = 0;
        for (; j <= i - 4; j += 4) {
            #pragma omp simd
            for (int k = 0; k < 4; ++k) {
                val -= flat_L[row_off + j + k] * x[j + k];
            }
        }
        /* Handle remaining elements */
        for (; j <= i; ++j) {
            val -= flat_L[row_off + j] * x[j];
        }
        x[i] = val / flat_L[row_off + i];
    }
}
