```cpp
#include <vector>
#include <algorithm>
#include <cstddef>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
/*
  Original version by Dave Wonnacott at Haverford College <davew@cs.haverford.edu>,
  with help from Allison Lake, Ting Zhou, and Tian Jin,
  based on algorithm by Nussinov, described in Allison Lake's senior thesis.
*/

void kernel_nussinov(int n, std::vector<int>& seq,
		     std::vector<std::vector<int>>& table) {

    // Local copy for speed
    const int* seq_ptr = seq.data();
    std::vector<std::vector<int>>* table_ptr = &table;

    const auto match = [](int b1, int b2) { return (b1 + b2 == 3) ? 1 : 0; };

    // The algorithm proceeds by increasing sub‑problem length
    for (int len = 2; len <= n; ++len) {            // sub‑problem length
        const int max_i = n - len;                  // i + len == j
#pragma omp parallel for schedule(static)
        for (int i = 0; i <= max_i; ++i) {
            int j = i + len;

            int best = table[i][j - 1];            // skip j
            best = std::max(best, table[i + 1][j]); // skip i

            // i matches j
            if (i + 1 <= j - 1) {                   // there is a gap
                best = std::max(best,
                                table[i + 1][j - 1] + match(seq_ptr[i], seq_ptr[j]));
            } else {                               // no gap
                best = std::max(best,
                                table[i + 1][j - 1] + match(seq_ptr[i], seq_ptr[j]));
            }

            // split at k
            for (int k = i + 1; k < j; ++k) {
                best = std::max(best, table[i][k] + table[k + 1][j]);
            }

            table[i][j] = best;
        }
    }
}
