gesummv:
```cpp
#include <vector>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_gesummv(int n,
                    double alpha,
                    double beta,
                    std::vector<std::vector<double>>& A,
                    std::vector<std::vector<double>>& B,
                    std::vector<double>& tmp,
                    std::vector<double>& x,
                    std::vector<double>& y)
{
    /* Parallelise the outer loop – each iteration is independent. */
#pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double tmp_i  = 0.0;
        double y_i    = 0.0;
        double *Ai    = A[i].data();   // pointer to the i‑th row of A
        double *Bi    = B[i].data();   // pointer to the i‑th row of B
        double *x_ptr = x.data();      // pointer to vector x

        /* Unroll the inner loop by a factor of 4 for a small speed boost. */
        int j = 0;
        for (; j <= n - 4; j += 4) {
            double x0 = x_ptr[j];
            double x1 = x_ptr[j + 1];
            double x2 = x_ptr[j + 2];
            double x3 = x_ptr[j + 3];

            tmp_i += Ai[j]     * x0 + Ai[j + 1]     * x1 +
                     Ai[j + 2] * x2 + Ai[j + 3]     * x3;

            y_i   += Bi[j]     * x0 + Bi[j + 1]     * x1 +
                     Bi[j + 2] * x2 + Bi[j + 3]     * x3;
        }

        /* Handle the remaining iterations (if n is not a multiple of 4). */
        for (; j < n; ++j) {
            tmp_i += Ai[j] * x_ptr[j];
            y_i   += Bi[j] * x_ptr[j];
        }

        tmp[i] = tmp_i;
        y[i]   = alpha * tmp_i + beta * y_i;
    }
}
