void kernel_lu(int n, std::vector<std::vector<double>>& A) {
    // Access the underlying contiguous memory if possible
    double* data = nullptr;
    if (!A.empty() && !A[0].empty() && A[0].size() == static_cast<std::size_t>(n)) {
        data = &A[0][0];
    }
    // Fallback to non‑contiguous access if memory is not contiguous
    auto get = [&](int i, int j) -> double& {
        return data ? data[i * n + j] : A[i][j];
    };

    // Parallelize the outermost loop; static scheduling works well for this
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        // Part 1: j < i
        for (int j = 0; j < i; ++j) {
            double* Aj = data ? data + i * n + j : &A[i][j];
            double* Ai0 = data ? data + i * n : &A[i][0];
            double* Akj = nullptr;
            for (int k = 0; k < j; ++k) {
                if (data) Akj = data + k * n + j;
                else       Akj = &A[k][j];
                *Aj -= Ai0[k] * (*Akj);
            }
            *Aj /= get(j, j);
        }
        // Part 2: j >= i
        for (int j = i; j < n; ++j) {
            double* Aj = data ? data + i * n + j : &A[i][j];
            double* Ai0 = data ? data + i * n : &A[i][0];
            for (int k = 0; k < i; ++k) {
                double* Akj = data ? data + k * n + j : &A[k][j];
                *Aj -= Ai0[k] * (*Akj);
            }
        }
    }
}
