#include <vector>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_trmm(int m, int n,
                 double alpha,
                 std::vector<std::vector<double>>& A,
                 std::vector<std::vector<double>>& B)
{
    // Form  B := alpha*A**T*B.
    // A is MxM, B is MxN
    // Loop ordering is chosen to maximize cache reuse.
#pragma omp parallel for schedule(static)
    for (int i = 0; i < m; ++i) {
        double* Bi = B[i].data();          // pointer to the i‑th row of B
        // For each column j
        for (int j = 0; j < n; ++j) {
            // Start with the existing value of B[i][j]
            double acc = Bi[j];
            // Accumulate contributions from rows k > i
            for (int k = i + 1; k < m; ++k) {
                acc += A[k][i] * B[k][j];
            }
            // Scale by alpha
            Bi[j] = alpha * acc;
        }
    }
}
