/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_syrk(int n, int m,
                 double alpha,
                 double beta,
                 std::vector<std::vector<double>>& C,
                 std::vector<std::vector<double>>& A) {
    /* ------------------------------------------------------------
       * The original code updates only the lower‑triangular part of
       * C (C[i][j] for j <= i).  We keep that exact logic, but we
       * accelerate it by:
       *
       * 1. Parallelising over the outer loop (rows of C) with OpenMP.
       * 2. Using contiguous sub‑vectors for C[i] and A[i] to avoid
       *    extra pointer indirections.
       * 3. Blocking the inner product over k to improve cache reuse
       *    (block size chosen to fit into L1 cache).
       *
       * The function signature cannot be changed, so the
       * reference type must stay `std::vector<std::vector<double>>`.
       * ------------------------------------------------------------
    */

    const int block = 64;                 // block size (tuned for L1 cache)
    const int n_omp = n;                  // number of rows

    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n_omp; ++i) {
        std::vector<double>& Ci = C[i];
        const std::vector<double>& Ai = A[i];

        /* 1. Scale the existing lower‑triangular part by beta */
        for (int j = 0; j <= i; ++j) {
            Ci[j] *= beta;
        }

        /* 2. Accumulate alpha * A[i][k] * A[j][k] for k = 0 .. m-1 */
        for (int k = 0; k < m; k += block) {
            int k_end = (k + block < m) ? k + block : m;

            /* Loop over the block for k */
            for (int kk = k; kk < k_end; ++kk) {
                double aik = Ai[kk] * alpha; // pre‑multiply once per i,k
                const std::vector<double>* Aptr = &A[0]; // will advance

                /* For each j in 0..i, accumulate aik * A[j][kk] */
                for (int j = 0; j <= i; ++j) {
                    Ci[j] += aik * (*Aptr)[kk];
                }
            }
        }
    }
}
