/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_jacobi_2d(int tsteps,
                      int n,
                      std::vector<std::vector<double>>& A,
                      std::vector<std::vector<double>>& B) {
    const double coef = 0.2;

    // Main loop over time steps
    for (int t = 0; t < tsteps; ++t) {
        // First half‑step: A -> B
#pragma omp parallel for schedule(static) firstprivate(coef)
        for (int i = 1; i < n - 1; ++i) {
            double* Ai     = A[i].data();
            double* Ai_prev = A[i - 1].data();
            double* Ai_next = A[i + 1].data();
            double* Bi     = B[i].data();

            // Iterate over the interior columns
            for (int j = 1; j < n - 1; ++j) {
                Bi[j] = coef * (Ai[j] +
                                Ai[j - 1] +
                                Ai[j + 1] +
                                Ai_next[j] +
                                Ai_prev[j]);
            }
        }

        // Second half‑step: B -> A
#pragma omp parallel for schedule(static) firstprivate(coef)
        for (int i = 1; i < n - 1; ++i) {
            double* Bi     = B[i].data();
            double* Bi_prev = B[i - 1].data();
            double* Bi_next = B[i + 1].data();
            double* Ai     = A[i].data();

            for (int j = 1; j < n - 1; ++j) {
                Ai[j] = coef * (Bi[j] +
                                Bi[j - 1] +
                                Bi[j + 1] +
                                Bi_next[j] +
                                Bi_prev[j]);
            }
        }
    }
}
