#include <vector>
#include <immintrin.h>

void kernel_durbin(int n, std::vector<double>& r, std::vector<double>& y)
{
    // allocate temporary working space only once
    std::vector<double> z(n, 0.0);

    // initialise first element
    y[0]   = -r[0];
    double beta  = 1.0;
    double alpha = -r[0];

    for (int k = 1; k < n; ++k) {
        // update beta
        beta = (1.0 - alpha * alpha) * beta;

        // compute the dot‑product sum
        double sum = 0.0;
        // use vectorised accumulation (AVX2)
        const int simd = 4;  // 4 doubles per __m256d
        int i = 0;
        __m256d vsum = _mm256_setzero_pd();
        for (; i <= k - simd; i += simd) {
            __m256d vr  = _mm256_loadu_pd(&r[k - i - 1]);   // r[k-1-i ... k-simd-i]
            __m256d vy  = _mm256_loadu_pd(&y[i]);           // y[i ... i+3]
            vsum = _mm256_fmadd_pd(vr, vy, vsum);          // manual fused multiply‑add
        }
        // horizontal sum of vsum
        alignas(32) double tmp[4];
        _mm256_store_pd(tmp, vsum);
        for (int j = 0; j < 4; ++j) sum += tmp[j];
        // tail
        for (; i < k; ++i) sum += r[k - i - 1] * y[i];

        // update alpha
        alpha = -(r[k] + sum) / beta;

        // compute z[i] = y[i] + alpha * y[k-1-i]
        for (i = 0; i <= k - simd; i += simd) {
            __m256d vy1 = _mm256_loadu_pd(&y[i]);
            __m256d vy2 = _mm256_loadu_pd(&y[k - 1 - i - 3]); // reversed index
            __m256d valpha = _mm256_set1_pd(alpha);
            __m256d vtmp   = _mm256_fmadd_pd(valpha, vy2, vy1);
            _mm256_storeu_pd(&z[i], vtmp);
        }
        for (; i < k; ++i) {
            z[i] = y[i] + alpha * y[k - 1 - i];
        }

        // copy z back to y
        for (i = 0; i < k; ++i) y[i] = z[i];

        y[k] = alpha;
    }
}
