void kernel_correlation(int m, int n,
                        std::vector<std::vector<double>>& data,
                        std::vector<std::vector<double>>& corr,
                        std::vector<double>& mean,
                        std::vector<double>& stddev)
{
    constexpr double eps = 0.1;
    const double inv_sqrt_n = 1.0 / std::sqrt(static_cast<double>(n));

    /* === Step 1: compute column means (parallel over columns) === */
#pragma omp parallel for
    for (int j = 0; j < m; ++j) {
        double sum = 0.0;
        for (int i = 0; i < n; ++i) {
            sum += data[i][j];
        }
        mean[j] = sum / static_cast<double>(n);
    }

    /* === Step 2: compute column stddevs (parallel over columns) === */
#pragma omp parallel for
    for (int j = 0; j < m; ++j) {
        double sum = 0.0;
        const double mu = mean[j];
        for (int i = 0; i < n; ++i) {
            const double diff = data[i][j] - mu;
            sum += diff * diff;
        }
        double sd = std::sqrt(sum / static_cast<double>(n));
        stddev[j] = (sd <= eps) ? 1.0 : sd;
    }

    /* === Step 3: normalize data (parallel over rows) === */
#pragma omp parallel for
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < m; ++j) {
            double val = data[i][j] - mean[j];
            val *= inv_sqrt_n;
            val /= stddev[j];
            data[i][j] = val;
        }
    }

    /* === Step 4: compute correlation matrix (symmetric) === */
    /* We compute only upper triangle; lower is filled by symmetry. */
#pragma omp parallel for collapse(2)
    for (int i = 0; i < m; ++i) {
        corr[i][i] = 1.0;               // diagonal
        for (int j = i + 1; j < m; ++j) {
            double sum = 0.0;
            for (int k = 0; k < n; ++k) {
                sum += data[k][i] * data[k][j];
            }
            corr[i][j] = sum;
            corr[j][i] = sum;            // symmetry
        }
    }
}
