// Optimised Seidel kernel – preserves exact sequential semantics
void kernel_seidel_2d(int tsteps,
                      int n,
                      std::vector<std::vector<double>>& A) {
    const double inv9 = 1.0 / 9.0;          // pre‑compute reciprocal
    for (int t = 0; t < tsteps; ++t) {
        for (int i = 1; i <= n - 2; ++i) {
            double* row   = A[i].data();
            double* rowm1 = A[i-1].data();
            double* rowp1 = A[i+1].data();
            for (int j = 1; j <= n - 2; ++j) {
                // sum of the 3×3 neighbourhood
                double s = rowm1[j-1] + rowm1[j] + rowm1[j+1] +
                           row[j-1]   + row[j]   + row[j+1]   +
                           rowp1[j-1] + rowp1[j] + rowp1[j+1];
                row[j] = s * inv9;
            }
        }
