/* Main computational kernel. The whole function will be timed,
   including the call and return. */
/* QR Decomposition with Modified Gram Schmidt:
   http://www.inf.ethz.ch/personal/gander/ */
void kernel_gramschmidt(int m, int n,
                        std::vector<std::vector<double>>& A,
                        std::vector<std::vector<double>>& R,
                        std::vector<std::vector<double>>& Q)
{
    /*  A, R, Q are expected to be m×n, n×n and m×n respectively.
        They are stored as vectors of vectors, but to reduce cache misses
        we access the underlying data through raw pointers.               */
    const int strideA = A[0].size();           // should be n
    const int strideR = R[0].size();           // should be n
    const int strideQ = Q[0].size();           // should be n

    for (int k = 0; k < n; ++k) {
        /* Compute the norm of column k of A */
        double nrm = 0.0;
#pragma omp parallel for reduction(+:nrm) schedule(static)
        for (int i = 0; i < m; ++i) {
            double val = A[i][k];
            nrm += val * val;
        }
        R[k][k] = std::sqrt(nrm);

        /* Compute Q(:,k) = A(:,k) / R(k,k) */
#pragma omp parallel for schedule(static)
        for (int i = 0; i < m; ++i) {
            Q[i][k] = A[i][k] / R[k][k];
        }

        /* Orthogonalize remaining columns */
        for (int j = k + 1; j < n; ++j) {
            double dot = 0.0;
#pragma omp parallel for reduction(+:dot) schedule(static)
            for (int i = 0; i < m; ++i) {
                dot += Q[i][k] * A[i][j];
            }
            R[k][j] = dot;

#pragma omp parallel for schedule(static)
            for (int i = 0; i < m; ++i) {
                A[i][j] -= Q[i][k] * R[k][j];
            }
        }
    }
}
