// Helper to flatten a 2‑D std::vector (row major) into a single std::vector
static inline void flatten(const std::vector<std::vector<double>>& src, std::vector<double>& dst)
{
    const size_t rows = src.size();
    const size_t cols = rows ? src[0].size() : 0;
    dst.resize(rows * cols);
    for (size_t i = 0; i < rows; ++i)
        std::copy(src[i].begin(), src[i].end(), dst.begin() + i * cols);
}

// Helper to copy back the flattened result
static inline void unflatten(const std::vector<double>& src,
                             std::vector<std::vector<double>>& dst)
{
    const size_t rows = dst.size();
    const size_t cols = rows ? dst[0].size() : 0;
    for (size_t i = 0; i < rows; ++i)
        std::copy(src.begin() + i * cols, src.begin() + (i + 1) * cols,
                  dst[i].begin());
}

void kernel_gemm(int ni, int nj, int nk,
                 double alpha,
                 double beta,
                 std::vector<std::vector<double>>& A,
                 std::vector<std::vector<double>>& B,
                 std::vector<std::vector<double>>& C)
{
    // Flatten input matrices to row‑major 1‑D arrays for contiguous memory access
    std::vector<double> flatA, flatB, flatC;
    flatten(A, flatA);
    flatten(B, flatB);
    flatten(C, flatC);

    const size_t lda = nk;           // A[i][k] -> flatA[i*lda + k]
    const size_t ldb = nj;           // B[k][j] -> flatB[k*ldb + j]
    const size_t ldc = nj;           // C[i][j] -> flatC[i*ldc + j]

    // OpenMP parallelisation over the outer i‑loop
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < ni; ++i) {
        double* Ci = flatC.data() + static_cast<size_t>(i) * ldc;
        const double* Ai = flatA.data() + static_cast<size_t>(i) * lda;

        // Scale C[i][j] by beta
        for (int j = 0; j < nj; ++j)
            Ci[j] *= beta;

        // Compute alpha * A[i,:] * B + beta * C[i,:]
        for (int k = 0; k < nk; ++k) {
            const double aik = alpha * Ai[k];
            const double* Bj = flatB.data() + static_cast<size_t>(k) * ldb;
            for (int j = 0; j < nj; ++j)
                Ci[j] += aik * Bj[j];
        }
    }

    // Copy the result back into the original C matrix
    unflatten(flatC, C);
}
