// Optimized kernel_covariance.cpp (gcc -O2 -fopenmp)

#include <vector>
#include <cmath>
#include <omp.h>

// -----------------------------------------------------------------------------
// Helper to flatten a 2‑D vector into a contiguous array for cache efficiency.
// The caller must ensure that the backing storage has at least m*n elements.
// -----------------------------------------------------------------------------
static inline double& flat(std::vector<double> &buf, int i, int j, int m) {
    return buf[i * m + j];
}

// -----------------------------------------------------------------------------
// Main kernel (signature required by the harness)
// -----------------------------------------------------------------------------
void kernel_covariance(int m, int n,
                       std::vector<std::vector<double>>& data,
                       std::vector<std::vector<double>>& cov,
                       std::vector<double>& mean)
{
    // ---------------------------------------------------------------------
    // 1. Pre‑allocate contiguous storage for data and covariance
    // ---------------------------------------------------------------------
    std::vector<double> data_flat(m * n);
    std::vector<double> cov_flat(m * m);

    // Copy input data to a flat array (row major: rows = i, columns = j)
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < m; ++j) {
            flat(data_flat, i, j, m) = data[i][j];
        }
    }

    // ---------------------------------------------------------------------
    // 2. Compute mean per dimension (column)
    // ---------------------------------------------------------------------
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < m; ++j) {
        double sum = 0.0;
        for (int i = 0; i < n; ++i) {
            sum += flat(data_flat, i, j, m);
        }
        mean[j] = sum / n;
    }

    // ---------------------------------------------------------------------
    // 3. Center data: subtract mean from each entry
    // ---------------------------------------------------------------------
    #pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < n; ++i)
        for (int j = 0; j < m; ++j)
            flat(data_flat, i, j, m) -= mean[j];

    // ---------------------------------------------------------------------
    // 4. Compute covariance matrix (upper triangle only, then symmetrize)
    // ---------------------------------------------------------------------
    double n1 = static_cast<double>(n - 1);
    #pragma omp parallel for schedule(static) collapse(2)
    for (int i = 0; i < m; ++i) {
        for (int j = i; j < m; ++j) {
            double s = 0.0;
            for (int k = 0; k < n; ++k) {
                s += flat(data_flat, k, i, m) * flat(data_flat, k, j, m);
            }
            s /= n1;
            flat(cov_flat, i, j, m) = s;
            flat(cov_flat, j, i, m) = s;   // full symmetry
        }
    }

    // ---------------------------------------------------------------------
    // 5. Copy results back to original 2‑D containers
    // ---------------------------------------------------------------------
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < m; ++i) {
        for (int j = 0; j < m; ++j) {
            cov[i][j] = flat(cov_flat, i, j, m);
        }
    }
}
