/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_3mm(int ni, int nj, int nk, int nl, int nm,
        std::vector<std::vector<double>>& E,
        std::vector<std::vector<double>>& A,
        std::vector<std::vector<double>>& B,
        std::vector<std::vector<double>>& F,
        std::vector<std::vector<double>>& C,
        std::vector<std::vector<double>>& D,
        std::vector<std::vector<double>>& G) {

    /* use contiguous storage pointers for faster access */
    double* e = &E[0][0];
    double* a = &A[0][0];
    double* b = &B[0][0];
    double* f = &F[0][0];
    double* c = &C[0][0];
    double* d = &D[0][0];
    double* g = &G[0][0];

    /* ---------- 1st multiply:  E = A * B  (ni×nj)  ---------- */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < ni; ++i) {
        double* e_row = e + (size_t)i * nj;
        const double* a_row = a + (size_t)i * nk;
        for (int j = 0; j < nj; ++j) {
            double sum = 0.0;
            for (int k = 0; k < nk; ++k)
                sum += a_row[k] * b[(size_t)k * nj + j];
            e_row[j] = sum;
        }
    }

    /* ---------- 2nd multiply:  F = C * D  (nj×nl)  ---------- */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < nj; ++i) {
        double* f_row = f + (size_t)i * nl;
        const double* c_row = c + (size_t)i * nm;
        for (int j = 0; j < nl; ++j) {
            double sum = 0.0;
            for (int k = 0; k < nm; ++k)
                sum += c_row[k] * d[(size_t)k * nl + j];
            f_row[j] = sum;
        }
    }

    /* ---------- 3rd multiply:  G = E * F  (ni×nl)  ---------- */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < ni; ++i) {
        double* g_row = g + (size_t)i * nl;
        const double* e_row = e + (size_t)i * nj;
        for (int j = 0; j < nl; ++j) {
            double sum = 0.0;
            for (int k = 0; k < nj; ++k)
                sum += e_row[k] * f[(size_t)k * nl + j];
            g_row[j] = sum;
        }
    }
