/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_doitgen(int nr, int nq, int np,
                    std::vector<std::vector<std::vector<double>>>& A,
                    std::vector<std::vector<double>>& C4,
                    std::vector<double>& sum) {
    /* Parallelise the outer two loops that have no inter‑iteration
       dependence.  The innermost loop is short so we keep it
       sequential to avoid the overhead of a nested parallel region. */
#pragma omp parallel for collapse(2) schedule(static)
    for (int r = 0; r < nr; ++r) {
        for (int q = 0; q < nq; ++q) {
            /* Access the contiguous rows of A and C4 directly */
            double* const a_vec = A[r][q].data();          // A[r][q][*]
            const std::vector<double>* const c4_rows = C4.data(); // C4[s][p]

            /* Reuse 'sum' vector as a temporary buffer for the current
               (r,q) pair.  The original array is overwritten later, so the
               content after the loop is irrelevant. */
            std::fill(sum.begin(), sum.begin() + np, 0.0);

            for (int s = 0; s < np; ++s) {
                const double* const c4_row = c4_rows[s].data(); // C4[s][*]
                const double a_val = a_vec[s];
                for (int p = 0; p < np; ++p) {
                    sum[p] += a_val * c4_row[p];
                }
            }

            /* Write the result back into A[r][q][*] */
            double* const a_dst = A[r][q].data();
            for (int p = 0; p < np; ++p) {
                a_dst[p] = sum[p];
            }
        }
    }
}
