/*
 * 3‑D heat kernel
 * A and B are stored as std::vector<std::vector<std::vector<double>>>.
 * Work is done by iterating over the interior cells only.
 * Loop order is rearranged for better cache locality and the
 * inner loops are parallelised with OpenMP.
 */
void kernel_heat_3d(int tsteps,
                    int n,
                    std::vector<std::vector<std::vector<double>>>& A,
                    std::vector<std::vector<std::vector<double>>>& B)
{
    const double coef = 0.125;

    for (int t = 1; t <= tsteps; ++t)
    {
        /* 1st half‑step: A -> B  */
        #pragma omp parallel for collapse(3) schedule(static)
        for (int i = 1; i < n - 1; ++i)
        {
            for (int j = 1; j < n - 1; ++j)
            {
                /* get inner pointers once per i / j */
                double *a_pp   = &A[i    ][j    ][0];
                double *a_pp1  = &A[i + 1][j    ][0];
                double *a_pp_1 = &A[i - 1][j    ][0];
                double *b_prev = &B[i    ][j    ][0];
                double *b_pp   = &B[i    ][j + 1][0];
                double *b_pm   = &B[i    ][j - 1][0];

                for (int k = 1; k < n - 1; ++k)
                {
                    double val = coef * (a_pp1[k] - 2.0 * a_pp[k] + a_pp_1[k])   // i‑dir
                               + coef * (b_pp[k]   - 2.0 * b_prev[k] + b_pm[k])   // j‑dir
                               + coef * (B[i][j][k+1] - 2.0 * B[i][j][k] + B[i][j][k-1]) // k‑dir
                               + A[i][j][k];
                    B[i][j][k] = val;
                }
            }
        }

        /* 2nd half‑step: B -> A  */
        #pragma omp parallel for collapse(3) schedule(static)
        for (int i = 1; i < n - 1; ++i)
        {
            for (int j = 1; j < n - 1; ++j)
            {
                double *b_pp   = &B[i    ][j    ][0];
                double *b_pp1  = &B[i + 1][j    ][0];
                double *b_pp_1 = &B[i - 1][j    ][0];
                double *a_prev = &A[i    ][j    ][0];
                double *a_pp   = &A[i    ][j + 1][0];
                double *a_pm   = &A[i    ][j - 1][0];

                for (int k = 1; k < n - 1; ++k)
                {
                    double val = coef * (b_pp1[k] - 2.0 * b_pp[k] + b_pp_1[k])   // i‑dir
                               + coef * (a_pp[k]   - 2.0 * a_prev[k] + a_pm[k])   // j‑dir
                               + coef * (A[i][j][k+1] - 2.0 * A[i][j][k] + A[i][j][k-1]) // k‑dir
                               + B[i][j][k];
                    A[i][j][k] = val;
                }
            }
        }
    }
}
