void kernel_fdtd_2d(int tmax,
                    int nx,
                    int ny,
                    std::vector<std::vector<double>>& ex,
                    std::vector<std::vector<double>>& ey,
                    std::vector<std::vector<double>>& hz,
                    std::vector<double>& _fict_) {
    const double coeff_ey = 0.5;
    const double coeff_ex = 0.5;
    const double coeff_hz = 0.7;

    // In order to avoid the cost of bounds checks on std::vector::operator[],
    // we will keep raw pointers to each row. This is safe because the
    // vectors are not re‑allocated inside the routine.
    std::vector<double*> ex_row_ptr(nx), ey_row_ptr(nx), hz_row_ptr(nx);
    for (int i = 0; i < nx; ++i) {
        ex_row_ptr[i]  = ex[i].data();
        ey_row_ptr[i]  = ey[i].data();
        hz_row_ptr[i]  = hz[i].data();
    }

    // The main time‑stepping loop is fully parallelized with OpenMP.
    // Each iteration is independent, so a static schedule gives good
    // load balancing on 8 cores.
#pragma omp parallel for schedule(static)
    for (int t = 0; t < tmax; ++t) {
        const double fic = _fict_[t];

        // 1. Set boundary values of ey[0][j]
#pragma omp for schedule(static)
        for (int j = 0; j < ny; ++j) {
            ey_row_ptr[0][j] = fic;
        }

        // 2. Update ey[i][j] for i>=1
#pragma omp for collapse(2) schedule(static)
        for (int i = 1; i < nx; ++i) {
            double* ey_i   = ey_row_ptr[i];
            double* ey_im1 = ey_row_ptr[i-1];
            double* hz_i   = hz_row_ptr[i];
            double* hz_im1 = hz_row_ptr[i-1];
            for (int j = 0; j < ny; ++j) {
                ey_i[j] -= coeff_ey * (hz_i[j] - hz_im1[j]);
            }
        }

        // 3. Update ex[i][j] for j>=1
#pragma omp for collapse(2) schedule(static)
        for (int i = 0; i < nx; ++i) {
            double* ex_i   = ex_row_ptr[i];
            double* hz_i   = hz_row_ptr[i];
            for (int j = 1; j < ny; ++j) {
                ex_i[j] -= coeff_ex * (hz_i[j] - hz_i[j-1]);
            }
        }

        // 4. Update hz[i][j] for i<nx-1 and j<ny-1
#pragma omp for collapse(2) schedule(static)
        for (int i = 0; i < nx - 1; ++i) {
            double* hz_i   = hz_row_ptr[i];
            double* hz_i1  = hz_row_ptr[i+1];
            double* ex_i   = ex_row_ptr[i];
            double* ey_i   = ey_row_ptr[i];
            double* ey_i1  = ey_row_ptr[i+1];
            for (int j = 0; j < ny - 1; ++j) {
                hz_i[j] -= coeff_hz *
                           (ex_i[j+1] - ex_i[j] + ey_i1[j] - ey_i[j]);
            }
        }
    }
