inline double& A_at(std::vector<std::vector<double>>& A, std::size_t i, std::size_t j) {
    return A[i][j];
}

void kernel_gemver(int n,
                   double alpha,
                   double beta,
                   std::vector<std::vector<double>>& A,
                   std::vector<double>& u1,
                   std::vector<double>& v1,
                   std::vector<double>& u2,
                   std::vector<double>& v2,
                   std::vector<double>& w,
                   std::vector<double>& x,
                   std::vector<double>& y,
                   std::vector<double>& z) 
{
    const std::size_t N = static_cast<std::size_t>(n);
    const std::size_t block = 64;          // cache block size (adjust if needed)

    /* 1. Update A with rank‑1 updates */
    #pragma omp parallel for collapse(2)
    for (std::size_t i = 0; i < N; ++i) {
        for (std::size_t j = 0; j < N; ++j) {
            double val = A_at(A,i,j);
            val += u1[i] * v1[j] + u2[i] * v2[j];
            A_at(A,i,j) = val;
        }
    }

    /* 2. x += beta * Aᵀ * y   (equivalent to the 2‑nd double loop) */
    #pragma omp parallel for
    for (std::size_t i = 0; i < N; ++i) {
        double sum = 0.0;
        #pragma omp simd
        for (std::size_t j = 0; j < N; ++j) {
            sum += A_at(A,j,i) * y[j];
        }
        x[i] += beta * sum;
    }

    /* 3. x += z */
    #pragma omp parallel for
    for (std::size_t i = 0; i < N; ++i) {
        x[i] += z[i];
    }

    /* 4. w += alpha * A * x   (block‑based for better cache locality) */
    #pragma omp parallel
    {
        double* w_local = new double[N]();   // thread‑private accumulation
        #pragma omp for nowait
        for (std::size_t i = 0; i < N; i += block) {
            std::size_t ib = std::min(block, N - i);
            for (std::size_t j = 0; j < N; j += block) {
                std::size_t jb = std::min(block, N - j);
                for (std::size_t ii = 0; ii < ib; ++ii) {
                    std::size_t ioff = i + ii;
                    double* wptr = &w_local[ioff];
                    const double* arow = reinterpret_cast<const double*>(&A[ioff][j]);
                    for (std::size_t jj = 0; jj < jb; ++jj) {
                        *wptr += alpha * arow[jj] * x[j + jj];
                    }
                }
            }
        }
        #pragma omp critical
        for (std::size_t i = 0; i < N; ++i) {
            w[i] += w_local[i];
        }
        delete[] w_local;
    }
}
