#include <vector>
#include <cstring>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
/* Based on a Fortran code fragment from Figure 5 of
 * "Automatic Data and Computation Decomposition on Distributed Memory Parallel Computers"
 * by Peizong Lee and Zvi Meir Kedem, TOPLAS, 2002
 *
 * The function signature is kept unchanged for compatibility with the harness.
 */
void kernel_adi(int tsteps, int n,
                std::vector<std::vector<double>>& u,
                std::vector<std::vector<double>>& v,
                std::vector<std::vector<double>>& p,
                std::vector<std::vector<double>>& q) {

    /* Flatten 2‑D vectors to 1‑D arrays for cache friendliness */
    const size_t N = static_cast<size_t>(n) * n;
    std::vector<double> fu(N), fv(N), fp(N), fq(N);

    /* Helper macros for linear indexing */
    #define IDX(i,j) ((static_cast<size_t>(i) * n + j))
    // copy input matrices into flattened arrays
    for (int i = 0; i < n; ++i)
        for (int j = 0; j < n; ++j) {
            fu[IDX(i,j)] = u[i][j];
            fv[IDX(i,j)] = v[i][j];
        }

    /* Pre‑compute constants */
    const double DX   = 1.0 / n;
    const double DY   = 1.0 / n;
    const double DT   = 1.0 / tsteps;
    const double B1   = 2.0;
    const double B2   = 1.0;
    const double mul1 = B1 * DT / (DX * DX);
    const double mul2 = B2 * DT / (DY * DY);
    const double a    = -mul1 / 2.0;
    const double b    = 1.0 + mul1;
    const double c    = a;
    const double d    = -mul2 / 2.0;
    const double e    = 1.0 + mul2;
    const double f    = d;

    /* Main time‑loop */
    for (int t = 1; t <= tsteps; ++t) {

        /* Solve along columns (v‑solve) */
        #pragma omp parallel for schedule(static)
        for (int i = 1; i < n-1; ++i) {
            /* Forward sweep: compute p[i][j] and q[i][j] */
            fp[IDX(i,0)] = 0.0;            // p[i][0]
            fq[IDX(i,0)] = fv[IDX(0,i)];   // q[i][0]

            for (int j = 1; j < n-1; ++j) {
                const double denom = a * fp[IDX(i,j-1)] + b;
                fp[IDX(i,j)] = -c / denom;
                const double num = (-d * fu[IDX(j,i-1)]
                                   + (1.0 + 2.0*d) * fu[IDX(j,i)]
                                   - f * fu[IDX(j,i+1)]
                                   - a * fq[IDX(i,j-1)]);
                fq[IDX(i,j)] = num / denom;
            }

            fv[IDX(n-1,i)] = 1.0;          // v[n-1][i]

            /* Backward sweep: compute v[j][i] */
            for (int j = n-2; j >= 1; --j) {
                fv[IDX(j,i)] = fp[IDX(i,j)] * fv[IDX(j+1,i)] + fq[IDX(i,j)];
            }
        }

        /* Solve along rows (u‑solve) */
        #pragma omp parallel for schedule(static)
        for (int i = 1; i < n-1; ++i) {
            fu[IDX(i,0)] = 1.0;            // u[i][0]
            fp[IDX(i,0)] = 0.0;            // p[i][0]
            fq[IDX(i,0)] = fu[IDX(i,0)];   // q[i][0]

            for (int j = 1; j < n-1; ++j) {
                const double denom = d * fp[IDX(i,j-1)] + e;
                fp[IDX(i,j)] = -f / denom;
                const double num = (-a * fv[IDX(i-1,j)]
                                   + (1.0 + 2.0*a) * fv[IDX(i,j)]
                                   - c * fv[IDX(i+1,j)]
                                   - d * fq[IDX(i,j-1)]);
                fq[IDX(i,j)] = num / denom;
            }

            fu[IDX(i,n-1)] = 1.0;          // u[i][n-1]

            /* Backward sweep: compute u[i][j] */
            for (int j = n-2; j >= 1; --j) {
                fu[IDX(i,j)] = fp[IDX(i,j)] * fu[IDX(i,j+1)] + fq[IDX(i,j)];
            }
        }
    }

    /* Copy results back to 2‑D std::vector matrices */
    for (int i = 0; i < n; ++i)
        for (int j = 0; j < n; ++j) {
            u[i][j] = fu[IDX(i,j)];
            v[i][j] = fv[IDX(i,j)];
        }

    #undef IDX
}
