```cpp
#include <cmath>
#include <vector>
#include <omp.h>

/* Optimised Deriche kernel – 8‑thread OpenMP implementation
 *
 * The function signature must match the harness, so we still
 * take std::vector<std::vector<float>>& parameters.
 * Inside we work directly on the row pointers for maximum cache
 * friendliness and parallelise the outer loops.
 */
void kernel_deriche(int w, int h, double alpha,
                    std::vector<std::vector<float>>& imgIn,
                    std::vector<std::vector<float>>& imgOut,
                    std::vector<std::vector<float>>& y1,
                    std::vector<std::vector<float>>& y2)
{
    /* Pre‑compute all filter constants once */
    const float expA  = std::exp(-alpha);
    const float exp2A = std::exp(-2.0 * alpha);

    const float k = 1.0f -
                    expA * (1.0f - expA) /
                    (1.0f + 2.0f * static_cast<float>(alpha) * expA - exp2A);

    const float a1 =  k;
    const float a2 =  k * expA * (static_cast<float>(alpha) - 1.0f);
    const float a3 =  k * expA * (static_cast<float>(alpha) + 1.0f);
    const float a4 = -k * exp2A;
    const float a5 =  k;
    const float a6 =  k * expA * (static_cast<float>(alpha) - 1.0f);
    const float a7 =  k * expA * (static_cast<float>(alpha) + 1.0f);
    const float a8 = -k * exp2A;

    const float b1 = std::pow(2.0, -alpha);
    const float b2 = -exp2A;
    const float c1 = 1.0f;
    const float c2 = 1.0f;

    /* ---- Row filtering (forward) ---- */
    #pragma omp parallel for
    for (int i = 0; i < w; ++i) {
        const float* const rowIn  = imgIn[i].data();
        float* const         rowY1 = y1[i].data();

        float ym1 = 0.0f, ym2 = 0.0f, xm1 = 0.0f;
        for (int j = 0; j < h; ++j) {
            const float in = rowIn[j];
            const float y  = a1 * in + a2 * xm1 + b1 * ym1 + b2 * ym2;
            rowY1[j] = y;
            xm1 = in;  ym2 = ym1;  ym1 = y;
        }
    }

    /* ---- Row filtering (backward) ---- */
    #pragma omp parallel for
    for (int i = 0; i < w; ++i) {
        const float* const rowIn  = imgIn[i].data();
        float* const         rowY2 = y2[i].data();

        float yp1 = 0.0f, yp2 = 0.0f, xp1 = 0.0f, xp2 = 0.0f;
        for (int j = h - 1; j >= 0; --j) {
            const float y = a3 * xp1 + a4 * xp2 + b1 * yp1 + b2 * yp2;
            rowY2[j] = y;
            xp2 = xp1;  xp1 = rowIn[j];
            yp2 = yp1;  yp1 = y;
        }
    }

    /* ---- Combine row results into imgOut ---- */
    #pragma omp parallel for collapse(2)
    for (int i = 0; i < w; ++i) {
        for (int j = 0; j < h; ++j) {
            imgOut[i][j] = c1 * (y1[i][j] + y2[i][j]);
        }
    }

    /* ---- Column filtering (forward) ---- */
    #pragma omp parallel for
    for (int j = 0; j < h; ++j) {
        float tm1 = 0.0f, ym1 = 0.0f, ym2 = 0.0f;
        for (int i = 0; i < w; ++i) {
            const float in = imgOut[i][j];
            float y = a5 * in + a6 * tm1 + b1 * ym1 + b2 * ym2;
            y1[i][j] = y;
            tm1 = in;  ym2 = ym1;  ym1 = y;
        }
    }

    /* ---- Column filtering (backward) ---- */
    #pragma omp parallel for
    for (int j = 0; j < h; ++j) {
        float tp1 = 0.0f, tp2 = 0.0f, yp1 = 0.0f, yp2 = 0.0f;
        for (int i = w - 1; i >= 0; --i) {
            float y = a7 * tp1 + a8 * tp2 + b1 * yp1 + b2 * yp2;
            y2[i][j] = y;
            tp2 = tp1;  tp1 = imgOut[i][j];
            yp2 = yp1;  yp1 = y;
        }
    }

    /* ---- Final combination ---- */
    #pragma omp parallel for collapse(2)
    for (int i = 0; i < w; ++i) {
        for (int j = 0; j < h; ++j) {
            imgOut[i][j] = c2 * (y1[i][j] + y2[i][j]);
        }
    }
}
